namespace sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Models;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    string Description,
    DateTimeOffset Timestamp);

using sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Models;

namespace sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Models;
using sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Services;

namespace sv_49272c0ce6c643ea9c6a7a4165c975ae.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Memphis, TN",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Package picked up", new DateTimeOffset(2026, 5, 23, 9, 0, 0, TimeSpan.Zero)),
                new("Arrived at sorting facility", new DateTimeOffset(2026, 5, 24, 3, 30, 0, TimeSpan.Zero)),
                new("Departed Memphis hub", new DateTimeOffset(2026, 5, 25, 6, 15, 0, TimeSpan.Zero)),
            }),

        ["TRK-002"] = new Shipment(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "Seattle, WA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 24, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Package picked up", new DateTimeOffset(2026, 5, 20, 10, 0, 0, TimeSpan.Zero)),
                new("In transit", new DateTimeOffset(2026, 5, 21, 14, 0, 0, TimeSpan.Zero)),
                new("Out for delivery", new DateTimeOffset(2026, 5, 24, 8, 0, 0, TimeSpan.Zero)),
                new("Delivered - left at front door", new DateTimeOffset(2026, 5, 24, 11, 42, 0, TimeSpan.Zero)),
            }),

        ["TRK-003"] = new Shipment(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Los Angeles, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Label created", new DateTimeOffset(2026, 5, 25, 8, 0, 0, TimeSpan.Zero)),
            }),
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

using sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Services;

namespace sv_49272c0ce6c643ea9c6a7a4165c975ae.Services;

public static class ShipmentApiEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        app.MapGet("/api/shipments/{trackingNumber}", async (
            string trackingNumber,
            IShipmentService service,
            CancellationToken ct) =>
        {
            try
            {
                var shipment = await service.GetShipmentAsync(trackingNumber, ct);
                return Results.Ok(shipment);
            }
            catch (KeyNotFoundException)
            {
                return Results.NotFound();
            }
        });
    }
}

using System.Net.Http.Json;
using sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Models;

namespace sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Services;

/// <summary>
/// HTTP-based implementation used when running on WebAssembly.
/// Calls back to the server API to fetch shipment data.
/// </summary>
public sealed class ShipmentServiceClient(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        var shipment = await response.Content.ReadFromJsonAsync<Shipment>(ct)
            ?? throw new InvalidOperationException("Failed to deserialize shipment response.");

        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Models
@using sv_49272c0ce6c643ea9c6a7a4165c975ae.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status History</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                    &mdash; @update.Description
                </li>
            }
        </ul>
    </div>
}

@code {
    private CancellationTokenSource? _cts;
    private Models.Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; nothing to do.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please check your connection and try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please check your connection and try again.";
        }
        catch (KeyNotFoundException ex)
        {
            Logger.LogWarning(ex, "Shipment not found: {TrackingNumber}", TrackingNumber);
            _errorMessage = $"Shipment '{TrackingNumber}' was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

